diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..709471feec5d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -6821,6 +6821,7 @@ static Instruction *foldReductionIdiom(ICmpInst &I,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   bool Changed = false;
   const SimplifyQuery Q = SQ.getWithInstruction(&I);
@@ -7082,6 +7083,37 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
     }
   }

+  // Fold icmp Pred (xor (xor A, AllOnes), B), (xor A, AllOnes) -> icmp NewPred (xor B, A), A
+  // where AllOnes is a constant with all bits set.
+  {
+    Value *A, *B;
+    const APInt *AllOnes;
+    if (match(Op0, m_Xor(m_Xor(m_Value(A), m_APInt(AllOnes)), m_Value(B))) &&
+        match(Op1, m_Xor(m_Specific(A), m_APInt(AllOnes))) &&
+        AllOnes->isAllOnes()) {
+      // (~A ^ B) Pred ~A -> (A ^ B) NewPred A
+      // For signed less-than: (~A ^ B) slt ~A -> (A ^ B) sgt A
+      // For signed greater-than: (~A ^ B) sgt ~A -> (A ^ B) slt A
+      // For other predicates, the transformation may not hold.
+      ICmpInst::Predicate NewPred;
+      switch (Pred) {
+      case ICmpInst::ICMP_SLT:
+        NewPred = ICmpInst::ICMP_SGT;
+        break;
+      case ICmpInst::ICMP_SGT:
+        NewPred = ICmpInst::ICMP_SLT;
+        break;
+      default:
+        NewPred = ICmpInst::BAD_ICMP_PREDICATE;
+        break;
+      }
+      if (NewPred != ICmpInst::BAD_ICMP_PREDICATE) {
+        Value *XorBA = Builder.CreateXor(B, A);
+        return new ICmpInst(NewPred, XorBA, A);
+      }
+    }
+  }
+
   if (Instruction *Res = foldICmpEquality(I))
     return Res;

@@ -7135,6 +7167,7 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   return Changed ? &I : nullptr;
 }

+
 /// Fold fcmp ([us]itofp x, cst) if possible.
 Instruction *InstCombinerImpl::foldFCmpIntToFPConst(FCmpInst &I,
                                                     Instruction *LHSI,

